sql:
SELECT AVG(aqd.no2_mean) AS overall_avg_no2
FROM air_quality_data aqd
JOIN demographic_data dd ON aqd.record_id = dd.record_id;

external_knowledge:
; User 2 refers to a specific user with a unique identifier of 2 in the user_access table; 
; Nitrogen Dioxide (NO2) is a common air pollutant that can have negative effects on the environment and human health; 
; Average NO2 levels can be used to assess the overall air quality of a region.

sql:
SELECT COUNT(*) AS high_pollution_instances
FROM air_quality_data
WHERE no2_mean > 20 AND o3_mean > 0.01;
